#pragma once

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <torch/extension.h>
#include <vector>

// Constants from specification
constexpr int NUM_QO_HEADS = 16;
constexpr int HEAD_DIM_CKV = 512;
constexpr int HEAD_DIM_KPE = 64;
constexpr int PAGE_SIZE = 1;
constexpr int BLOCK_SIZE = 128;
constexpr int KV_TILE_SIZE = 64;
constexpr int HEADS_TILE = 4;
constexpr int DIM_TILE_CKV = 64;
constexpr int DIM_TILE_KPE = 64;
constexpr int NUM_HEADS_TILES = NUM_QO_HEADS / HEADS_TILE;
constexpr int NUM_DIM_TILES_CKV = HEAD_DIM_CKV / DIM_TILE_CKV;
constexpr int NUM_DIM_TILES_KPE = HEAD_DIM_KPE / DIM_TILE_KPE;

// Kernel declaration
__global__ void mla_paged_prefill_kernel(
    const __nv_bfloat16* __restrict__ q_nope,
    const __nv_bfloat16* __restrict__ q_pe,
    const __nv_bfloat16* __restrict__ ckv_cache,
    const __nv_bfloat16* __restrict__ kpe_cache,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    float sm_scale,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    int total_q,
    int num_qo_heads,
    int head_dim_ckv,
    int head_dim_kpe,
    int len_indptr
);

// Host launcher function declaration
void launch_mla_paged_prefill_kernel(
    const __nv_bfloat16* q_nope,
    const __nv_bfloat16* q_pe,
    const __nv_bfloat16* ckv_cache,
    const __nv_bfloat16* kpe_cache,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    float sm_scale,
    __nv_bfloat16* output,
    float* lse,
    int total_q,
    int num_qo_heads,
    int head_dim_ckv,
    int head_dim_kpe,
    int len_indptr,
    int batch_size
);

// Host function declaration
std::vector<torch::Tensor> run(
    torch::Tensor q_nope,
    torch::Tensor q_pe,
    torch::Tensor ckv_cache,
    torch::Tensor kpe_cache,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    float sm_scale
);

#include "kernel.h"
#include <math_constants.h>
#include <math.h>

__device__ __forceinline__ float bf16_to_float(__nv_bfloat16 val) {
    return __bfloat162float(val);
}

__device__ __forceinline__ __nv_bfloat16 float_to_bf16(float val) {
    return __float2bfloat16(val);
}

__global__ void mla_paged_prefill_kernel(
    const __nv_bfloat16* __restrict__ q_nope,
    const __nv_bfloat16* __restrict__ q_pe,
    const __nv_bfloat16* __restrict__ ckv_cache,
    const __nv_bfloat16* __restrict__ kpe_cache,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    float sm_scale,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    int total_q,
    int num_qo_heads,
    int head_dim_ckv,
    int head_dim_kpe,
    int len_indptr
) {
    int seq_id = blockIdx.x;
    int batch_size = len_indptr - 1;

    if (seq_id >= batch_size) return;

    int q_start = qo_indptr[seq_id];
    int q_end = qo_indptr[seq_id + 1];
    int q_len = q_end - q_start;

    int kv_start = kv_indptr[seq_id];
    int kv_end = kv_indptr[seq_id + 1];
    int kv_len = kv_end - kv_start;

    if (q_len <= 0 || kv_len <= 0) return;

    int prefix_len = kv_len - q_len;

    // Shared memory for KV tiles
    extern __shared__ float smem_raw[];
    float* smem_kc = smem_raw;
    float* smem_kp = smem_raw + KV_TILE_SIZE * head_dim_ckv;

    // Grid-stride loop over queries in this sequence
    for (int q_offset = threadIdx.x; q_offset < q_len; q_offset += blockDim.x) {
        int q_idx = q_start + q_offset;
        int query_abs_pos = prefix_len + q_offset;

        // Initialize accumulators for each head
        float max_logits[NUM_QO_HEADS];
        float sum_exp[NUM_QO_HEADS];
        float out_acc[NUM_QO_HEADS][HEAD_DIM_CKV];

        for (int h = 0; h < NUM_QO_HEADS; ++h) {
            max_logits[h] = -1e20f;
            sum_exp[h] = 0.0f;
            for (int d = 0; d < HEAD_DIM_CKV; ++d) {
                out_acc[h][d] = 0.0f;
            }
        }

        // Load Q for this query position
        float q_nope_f[NUM_QO_HEADS][HEAD_DIM_CKV];
        float q_pe_f[NUM_QO_HEADS][HEAD_DIM_KPE];

        for (int h = 0; h < NUM_QO_HEADS; ++h) {
            const __nv_bfloat16* q_nope_ptr = q_nope + (q_idx * num_qo_heads + h) * head_dim_ckv;
            const __nv_bfloat16* q_pe_ptr = q_pe + (q_idx * num_qo_heads + h) * head_dim_kpe;

            for (int d = 0; d < HEAD_DIM_CKV; ++d) {
                q_nope_f[h][d] = bf16_to_float(q_nope_ptr[d]);
            }
            for (int d = 0; d < HEAD_DIM_KPE; ++d) {
                q_pe_f[h][d] = bf16_to_float(q_pe_ptr[d]);
            }
        }

        // Iterate over KV keys in tiles
        for (int k_tile = 0; k_tile < kv_len; k_tile += KV_TILE_SIZE) {
            int k_end = min(k_tile + KV_TILE_SIZE, kv_len);
            int tile_size = k_end - k_tile;

            // Load K tiles into shared memory
            for (int k = threadIdx.x; k < tile_size; k += blockDim.x) {
                int k_idx = k_tile + k;
                int page_id = kv_indices[kv_start + k_idx];

                // Load Kc
                const __nv_bfloat16* k_c_ptr = ckv_cache + (page_id * PAGE_SIZE + 0) * head_dim_ckv;
                for (int d = 0; d < head_dim_ckv; ++d) {
                    smem_kc[k * head_dim_ckv + d] = bf16_to_float(k_c_ptr[d]);
                }

                // Load Kp
                const __nv_bfloat16* k_p_ptr = kpe_cache + (page_id * PAGE_SIZE + 0) * head_dim_kpe;
                for (int d = 0; d < head_dim_kpe; ++d) {
                    smem_kp[k * head_dim_kpe + d] = bf16_to_float(k_p_ptr[d]);
                }
            }
            __syncthreads();

            // Compute attention for this tile
            for (int k = 0; k < tile_size; ++k) {
                int k_idx = k_tile + k;

                // Causal mask check
                bool is_causal = (k_idx <= query_abs_pos);

                if (!is_causal) continue;

                // Compute full logits for this key position
                for (int h = 0; h < NUM_QO_HEADS; ++h) {
                    float logit = 0.0f;

                    // Q_nope @ K_c
                    for (int d = 0; d < HEAD_DIM_CKV; ++d) {
                        logit += q_nope_f[h][d] * smem_kc[k * head_dim_ckv + d];
                    }

                    // Q_pe @ K_p
                    for (int d = 0; d < HEAD_DIM_KPE; ++d) {
                        logit += q_pe_f[h][d] * smem_kp[k * head_dim_kpe + d];
                    }

                    logit *= sm_scale;

                    // Online softmax update
                    float new_max = max(max_logits[h], logit);
                    float scale = expf(max_logits[h] - new_max);
                    float new_scale = expf(logit - new_max);

                    sum_exp[h] = sum_exp[h] * scale + new_scale;
                    max_logits[h] = new_max;

                    // Accumulate weighted K
                    float weight = new_scale;
                    for (int d = 0; d < HEAD_DIM_CKV; ++d) {
                        out_acc[h][d] += weight * smem_kc[k * head_dim_ckv + d];
                    }
                }
            }
            __syncthreads();
        }

        // Normalize and write output
        for (int h = 0; h < NUM_QO_HEADS; ++h) {
            float norm = 1.0f / sum_exp[h];

            // Write output
            __nv_bfloat16* out_ptr = output + (q_idx * num_qo_heads + h) * head_dim_ckv;
            for (int d = 0; d < HEAD_DIM_CKV; ++d) {
                out_ptr[d] = float_to_bf16(out_acc[h][d] * norm);
            }

            // Write LSE (2-base log-sum-exp)
            lse[q_idx * num_qo_heads + h] = max_logits[h] + logf(sum_exp[h]) / logf(2.0f);
        }
    }
}

void launch_mla_paged_prefill_kernel(
    const __nv_bfloat16* q_nope,
    const __nv_bfloat16* q_pe,
    const __nv_bfloat16* ckv_cache,
    const __nv_bfloat16* kpe_cache,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    float sm_scale,
    __nv_bfloat16* output,
    float* lse,
    int total_q,
    int num_qo_heads,
    int head_dim_ckv,
    int head_dim_kpe,
    int len_indptr,
    int batch_size
) {
    int shared_mem_size = KV_TILE_SIZE * head_dim_ckv * sizeof(float) + 
                          KV_TILE_SIZE * head_dim_kpe * sizeof(float);

    mla_paged_prefill_kernel<<<batch_size, BLOCK_SIZE, shared_mem_size>>>(
        q_nope, q_pe, ckv_cache, kpe_cache,
        qo_indptr, kv_indptr, kv_indices,
        sm_scale, output, lse,
        total_q, num_qo_heads, head_dim_ckv, head_dim_kpe, len_indptr
    );
}

#include <torch/extension.h>
#include "kernel.h"
#include <vector>
#include <cuda_bf16.h>

std::vector<torch::Tensor> run(
    torch::Tensor q_nope,
    torch::Tensor q_pe,
    torch::Tensor ckv_cache,
    torch::Tensor kpe_cache,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    float sm_scale
) {
    // Validate inputs
    TORCH_CHECK(q_nope.device().is_cuda(), "q_nope must be on CUDA");
    TORCH_CHECK(q_pe.device().is_cuda(), "q_pe must be on CUDA");
    TORCH_CHECK(ckv_cache.device().is_cuda(), "ckv_cache must be on CUDA");
    TORCH_CHECK(kpe_cache.device().is_cuda(), "kpe_cache must be on CUDA");
    TORCH_CHECK(qo_indptr.device().is_cuda(), "qo_indptr must be on CUDA");
    TORCH_CHECK(kv_indptr.device().is_cuda(), "kv_indptr must be on CUDA");
    TORCH_CHECK(kv_indices.device().is_cuda(), "kv_indices must be on CUDA");

    TORCH_CHECK(q_nope.dtype() == torch::kBFloat16, "q_nope must be bfloat16");
    TORCH_CHECK(q_pe.dtype() == torch::kBFloat16, "q_pe must be bfloat16");
    TORCH_CHECK(ckv_cache.dtype() == torch::kBFloat16, "ckv_cache must be bfloat16");
    TORCH_CHECK(kpe_cache.dtype() == torch::kBFloat16, "kpe_cache must be bfloat16");
    TORCH_CHECK(qo_indptr.dtype() == torch::kInt32, "qo_indptr must be int32");
    TORCH_CHECK(kv_indptr.dtype() == torch::kInt32, "kv_indptr must be int32");
    TORCH_CHECK(kv_indices.dtype() == torch::kInt32, "kv_indices must be int32");

    // Ensure contiguity to avoid indexing errors
    if (!q_nope.is_contiguous()) q_nope = q_nope.contiguous();
    if (!q_pe.is_contiguous()) q_pe = q_pe.contiguous();
    if (!ckv_cache.is_contiguous()) ckv_cache = ckv_cache.contiguous();
    if (!kpe_cache.is_contiguous()) kpe_cache = kpe_cache.contiguous();
    if (!qo_indptr.is_contiguous()) qo_indptr = qo_indptr.contiguous();
    if (!kv_indptr.is_contiguous()) kv_indptr = kv_indptr.contiguous();
    if (!kv_indices.is_contiguous()) kv_indices = kv_indices.contiguous();

    int total_q = q_nope.size(0);
    int num_qo_heads = q_nope.size(1);
    int head_dim_ckv = q_nope.size(2);
    int head_dim_kpe = q_pe.size(2);
    int len_indptr = qo_indptr.size(0);

    // Check constants
    TORCH_CHECK(num_qo_heads == 16, "num_qo_heads must be 16");
    TORCH_CHECK(head_dim_ckv == 512, "head_dim_ckv must be 512");
    TORCH_CHECK(head_dim_kpe == 64, "head_dim_kpe must be 64");
    TORCH_CHECK(ckv_cache.size(1) == 1, "page_size must be 1");

    // Check constraints
    TORCH_CHECK(total_q == qo_indptr[-1].item().toInt(), "total_q must equal qo_indptr[-1]");
    TORCH_CHECK(kv_indices.size(0) == kv_indptr[-1].item().toInt(), "num_kv_indices must equal kv_indptr[-1]");

    // Create output tensors
    auto output = torch::empty(
        {total_q, num_qo_heads, head_dim_ckv},
        torch::TensorOptions().dtype(torch::kBFloat16).device(q_nope.device())
    );
    auto lse = torch::empty(
        {total_q, num_qo_heads},
        torch::TensorOptions().dtype(torch::kFloat32).device(q_nope.device())
    );

    int batch_size = len_indptr - 1;

    // Launch kernel via helper function
    launch_mla_paged_prefill_kernel(
        reinterpret_cast<const __nv_bfloat16*>(q_nope.data_ptr<at::BFloat16>()),
        reinterpret_cast<const __nv_bfloat16*>(q_pe.data_ptr<at::BFloat16>()),
        reinterpret_cast<const __nv_bfloat16*>(ckv_cache.data_ptr<at::BFloat16>()),
        reinterpret_cast<const __nv_bfloat16*>(kpe_cache.data_ptr<at::BFloat16>()),
        qo_indptr.data_ptr<int32_t>(),
        kv_indptr.data_ptr<int32_t>(),
        kv_indices.data_ptr<int32_t>(),
        sm_scale,
        reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>()),
        lse.data_ptr<float>(),
        total_q,
        num_qo_heads,
        head_dim_ckv,
        head_dim_kpe,
        len_indptr,
        batch_size
    );

    // Check for CUDA errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel execution failed: ") + cudaGetErrorString(err));
    }

    return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "MLA Paged Prefill Causal Kernel");
}
